    "id": "remote-bind-without-guard",
    "severity": "HIGH",
    "category": "security",
    "location": "scripts/ai_agent_bridge/_cli.py:679",
    "description": "`--host` accepts arbitrary bind addresses and `uvicorn.run` uses them directly, so `ab serve --openai --host 0.0.0.0` exposes an unauthenticated HTTP endpoint that can invoke local agent CLIs using the user's credentials and repository context. For local-only tooling, non-loopback binds should require an explicit remote-enable flag or be rejected."
  },
  {
    "id": "unbounded-request-spawns-subprocesses",
    "severity": "MEDIUM",
    "category": "dos-surface",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:316",
    "description": "`/v1/chat/completions` accepts unbounded message counts and content sizes, then flattens the full payload and synchronously starts a backend subprocess per request with no body-size, prompt-size, or concurrency limits. A local or accidentally exposed client can consume memory, process slots, backend quota, and up to the full backend timeout per request."
  },
  {
    "id": "streaming-requests-return-nonstream-response",
    "severity": "MEDIUM",
    "category": "spec-compliance",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:316",
    "description": "The request model allows unknown OpenAI fields but `chat_completions` ignores `stream`; clients sending `stream: true` will receive a normal JSON completion with HTTP 200 instead of an SSE stream or an explicit unsupported-feature error. This breaks OpenAI-compatible clients that switch parsing behavior based on the requested streaming mode."
  },
  {
    "id": "prompt-passed-through-process-argv",
    "severity": "LOW",
    "category": "security",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:189",
    "description": "Gemini, Claude, and Hermes prompts are passed as command-line arguments rather than stdin or a temporary file. Request contents may include secrets and can be visible to local process-list observers while the subprocess runs; large prompts also risk OS argument-length failures before the backend receives the request."
  }
]

